import{_ as t}from"./_plugin-vue_export-helper.cdc0426e.js";import{o as a,c as d,a as o,b as e,d as p,e as c,r as i}from"./app.fea91a44.js";const s={},l=c('<h2 id="问题" tabindex="-1"><a class="header-anchor" href="#问题" aria-hidden="true">#</a> 问题</h2><p>之前写 react 项目时在开发阶段经常需要刷新页面，导致滚动位置重置，需要滚动一段距离才能回到原位置，时间长了也有点烦，所以想研究一下滚动恢复（PS：react-router-v6 提供了 ScrollRestoration），先想到的就是我博客的滚动恢复（博客是 vuepress 搭的），然后发现了一点违反直觉的事情。</p><p>vuepress 具体的滚动行为是这样的：一个新的页面默认滚动位置是 0，当你滚动时会记录滚动位置，当你刷新或在页面中导航时会恢复滚动位置。</p><p>看起来很正常，但滚动位置存储在了什么地方呢？要知道即使刷新并导航也不会丢失滚动位置，这肯定是需要将滚动位置保存的，但我使用 chrome 开发者工具翻遍了有关 storage 的地方都没有找到滚动位置记录的数据。而且还有一个值得注意的地方就是新开一个 tab 页签访问相同的网站，对应的滚动位置是默认的，即 0。</p><p>我把这个问题发到了一些编程群，诞生了以下讨论（内容较长，可以跳过不看）：</p><p><img src="http://qkc148.bvimg.com/18470/21c7c4f6b8407973.jpg" alt="1" loading="lazy"></p><p><img src="http://qkc148.bvimg.com/18470/53e20556118ae5c0.jpg" alt="2" loading="lazy"></p><p><img src="http://qkc148.bvimg.com/18470/359c388d57519b81.png" alt="3" loading="lazy"></p><p>讨论后得出的结果是 vuepress 将滚动位置保存在了 <code>history</code> 对象的 <code>state</code> 属性中，因为历史记录在刷新后是不会变的，所以才可以实现保存数据的功能，而不同的页签历史记录是不同的，也就可以解释为什么新开页签的页面不会有滚动恢复。</p><p><img src="http://qkc148.bvimg.com/18470/c7cc7b4132ab682e.png" alt="20230928154505" loading="lazy"></p><h2 id="溯源" tabindex="-1"><a class="header-anchor" href="#溯源" aria-hidden="true">#</a> 溯源</h2><p>有了线索我们就可以有针对性的去查找，我下载了 vuepress 的源码，针对路由部分进行搜索，找到了以下代码：</p><p><img src="http://qkc148.bvimg.com/18470/86be23928e48ad40.png" alt="20230928155025" loading="lazy"></p>',13),n={href:"https://router.vuejs.org/zh/guide/advanced/scroll-behavior.html",target:"_blank",rel:"noopener noreferrer"},h=c('<p>我们在 vue-router 找到 <code>pushWithRedirect</code> 函数，这个函数是 vue-router 中 <code>push</code> 和 <code>replace</code> 实际调用的函数：</p><p><img src="http://qkc148.bvimg.com/18470/07210775f147e664.png" alt="20230928160418" loading="lazy"></p><p><code>pushWithRedirect</code> 又调用了 <code>handleScroll</code>，在这里获取了保存的滚动位置：</p><p><img src="http://qkc148.bvimg.com/18470/7174051e9000aa10.png" alt="20230928160806" loading="lazy"></p><p>vue-router 会通过一个 <code>Map</code> 保存滚动位置，每个滚动位置的 <code>key</code> 都是对应页面的 <code>path</code>，当某个页面的滚动位置不在 <code>Map</code> 中时会去 <code>history.state.scroll</code> 中取。</p><p>有获取就有保存，vue-router 不是在滚动发生时实时保存滚动位置的，而是在离开当前页面时进行保存，<code>pushWithRedirect</code> 里还调用了 <code>finalizeNavigation</code> 方法：</p><p><img src="http://qkc148.bvimg.com/18470/346d1245a59cf92f.png" alt="20230928163837" loading="lazy"></p><p><code>routerHistory</code> 的初始化比较复杂，只需要知道这里他是 <code>history</code> 的副本就 ok 了，就是通过 h5 的 <code>pushState</code> 和 <code>replaceState</code> API 实现的。另外除了 <code>pushWithRedirect</code> 添加历史时会记录滚动位置，<code>history.popstate</code> 和 <code>window.beforeunload</code> 事件中都有对应的逻辑。</p>',8);function u(g,m){const r=i("ExternalLinkIcon");return a(),d("div",null,[l,o("p",null,[e("可以看到这种行为其实是 vue-router 提供的（不看文档的坏处），vue-router 提供了 "),o("a",n,[e("scroll-behavior"),p(r)]),e(" 的滚动恢复行为，我们再看 vue-router 的源码。")]),h])}const b=t(s,[["render",u],["__file","record_vuepress_rolling_recovery.html.vue"]]);export{b as default};
